import os
import re
from pathlib import Path
from flask import Flask, send_file, abort

app = Flask(__name__)

UPLOAD_DIR = Path("uploads").resolve()
ALLOWED_EXTENSIONS = {".pdf", ".doc", ".docx", ".txt", ".jpg", ".png", ".gif"}
FILE_ID_MAPPING = {}

def is_safe_path(base_path: Path, user_path: str) -> bool:
    try:
        full_path = (base_path / user_path).resolve()
        return full_path.is_relative_to(base_path)
    except Exception:
        return False

def get_file_path_from_id(file_id: str) -> Path:
    if file_id not in FILE_ID_MAPPING:
        return None
    return Path(FILE_ID_MAPPING[file_id])

def validate_filename(filename: str) -> bool:
    if not filename or filename.startswith("/") or ".." in filename:
        return False
    if not any(filename.endswith(ext) for ext in ALLOWED_EXTENSIONS):
        return False
    return True

@app.route('/legacy/<file_id>')
def serve_legacy_file(file_id: str):
    file_path = get_file_path_from_id(file_id)
    if not file_path:
        abort(404)
    
    if not file_path.exists():
        abort(404)
    
    if not is_safe_path(UPLOAD_DIR, file_path.relative_to(UPLOAD_DIR).as_posix()):
        abort(403)
    
    return send_file(file_path)

@app.route('/legacy/<path:filename>')
def serve_legacy_file_by_name(filename: str):
    if not validate_filename(filename):
        abort(400)
    
    file_path = UPLOAD_DIR / filename
    if not file_path.exists():
        abort(404)
    
    if not is_safe_path(UPLOAD_DIR, filename):
        abort(403)
    
    return send_file(file_path)